const { exec } = require('child_process');
const { AzureFunction, Context, HttpRequest } = require('@azure/functions');

const documentConverter: AzureFunction = async (context: Context, req: HttpRequest): Promise<void> => {
    context.log('Document conversion function processed a request.');

    const { inputFileName, outputFormat } = req.body;

    if (!inputFileName || !outputFormat) {
        context.res = {
            status: 400,
            body: "Please provide both inputFileName and outputFormat."
        };
        return;
    }

    const allowedFormats = ['pdf', 'docx', 'odt']; // Define allowed formats
    if (!allowedFormats.includes(outputFormat)) {
        context.res = {
            status: 400,
            body: "Invalid output format. Allowed formats are: pdf, docx, odt."
        };
        return;
    }

    const outputFileName = `${inputFileName.split('.').slice(0, -1).join('.')}.${outputFormat}`;
    const command = `libreoffice --headless --convert-to ${outputFormat} --outdir ${process.cwd()} ${inputFileName}`;

    exec(command, (error, stdout, stderr) => {
        if (error) {
            context.log(`Error: ${error.message}`);
            context.res = {
                status: 500,
                body: `Conversion failed: ${error.message}`
            };
            return;
        }
        if (stderr) {
            context.log(`Stderr: ${stderr}`);
        }

        context.res = {
            status: 200,
            body: `File converted successfully to ${outputFileName}`
        };
    });
};

export default documentConverter;